            { text: `${topic || 'Ali'} marketten 5 elma aldı, 3 tanesini yedi. Kaç elması kaldı?`, solution: "2" },
            { text: `Bir sınıfta 12 öğrenci var. 4 öğrenci daha gelirse toplam kaç öğrenci olur?`, solution: "16" }
        ]
    }));
};

